// Some portions generated by Codex
package org.eclipse.rdf4j.workbench.util;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.io.ByteArrayOutputStream;
import java.io.StringWriter;
import java.net.URL;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.QueryResultHandlerException;
import org.eclipse.rdf4j.query.resultio.sparqljson.SPARQLResultsJSONWriter;
import org.junit.jupiter.api.Test;

class TupleResultBuilderCoverageTest {

	@Test
	void workbenchWriterEmitsMetadataAndNamespaceFromWriterConstructor() throws Exception {
		StringWriter sink = new StringWriter();
		TupleResultBuilder builder = new TupleResultBuilder(new WorkbenchTupleResultWriter(sink),
				SimpleValueFactory.getInstance());

		builder.start("iri", "literal");
		builder.metadata("rows", 1);
		builder.metadata("ignored", null);
		builder.result(SimpleValueFactory.getInstance().createIRI("urn:test:item"), 7);
		builder.end();
		builder.flush();

		assertThat(sink.toString())
				.contains("xmlns:workbench='https://rdf4j.org/schema/workbench#'")
				.contains("<workbench:rows>1</workbench:rows>")
				.doesNotContain("ignored");
	}

	@Test
	void metadataIsNoOpForNonWorkbenchWriters() {
		TupleResultBuilder builder = new TupleResultBuilder(new SPARQLResultsJSONWriter(new ByteArrayOutputStream()),
				SimpleValueFactory.getInstance());

		assertThat(builder.metadata("rows", 1)).isSameAs(builder);
		builder.flush();
	}

	@Test
	void namedResultSupportsUrlsAndRejectsUnsupportedObjects() throws Exception {
		TupleResultBuilder urlBuilder = new TupleResultBuilder(new WorkbenchTupleResultWriter(new StringWriter()),
				SimpleValueFactory.getInstance());
		urlBuilder.start("value");
		urlBuilder.namedResult("value", new URL("https://example.org/item"));
		urlBuilder.end();

		TupleResultBuilder unsupportedBuilder = new TupleResultBuilder(
				new WorkbenchTupleResultWriter(new StringWriter()), SimpleValueFactory.getInstance());
		unsupportedBuilder.start("value");

		assertThatThrownBy(() -> unsupportedBuilder.namedResult("value", new Object()))
				.isInstanceOf(QueryResultHandlerException.class)
				.hasMessageContaining("Could not convert an object to a Value");
	}

	@Test
	void workbenchWriterWrapsNamespaceRegistrationFailures() {
		assertThatThrownBy(BrokenWorkbenchTupleResultWriter::new)
				.isInstanceOf(IllegalStateException.class)
				.hasCauseInstanceOf(QueryResultHandlerException.class)
				.hasMessageContaining("Could not register workbench result namespace");
	}

	private static final class BrokenWorkbenchTupleResultWriter extends WorkbenchTupleResultWriter {
		private BrokenWorkbenchTupleResultWriter() {
			super(new StringWriter());
		}

		@Override
		public void handleNamespace(String prefix, String uri) throws QueryResultHandlerException {
			throw new QueryResultHandlerException("boom");
		}
	}
}
